@strawberry.type
class Review:
    id: strawberry.ID
    author: str
    rating: int
    body: Optional[str]
    created_at: datetime


@strawberry.type
class Seller:
    id: strawberry.ID
    name: str
    rating: Optional[float]


@strawberry.type
class Category:
    id: strawberry.ID
    name: str


@strawberry.type
class Image:
    id: strawberry.ID
    url: str
    alt_text: Optional[str]


@strawberry.type
class Product:
    id: strawberry.ID
    name: str
    description: Optional[str]
    price: float
    created_at: datetime

    @strawberry.field
    def reviews(self, info) -> List[Review]:
        return [
            Review(
                id=str(r.id),
                author=r.author,
                rating=r.rating,
                body=r.body,
                created_at=r.created_at,
            )
            for r in self._model.reviews
        ]

    @strawberry.field
    def sellers(self, info) -> List[Seller]:
        return [
            Seller(
                id=str(s.id),
                name=s.name,
                rating=s.rating,
            )
            for s in self._model.sellers
        ]

    @strawberry.field
    def categories(self, info) -> List[Category]:
        return [
            Category(
                id=str(c.id),
                name=c.name,
            )
            for c in self._model.categories
        ]

    @strawberry.field
    def images(self, info) -> List[Image]:
        return [
            Image(
                id=str(i.id),
                url=i.url,
                alt_text=i.alt_text,
            )
            for i in self._model.images
        ]


def to_product(model: ProductModel) -> Product:
    product = Product(
        id=str(model.id),
        name=model.name,
        description=model.description,
        price=model.price,
        created_at=model.created_at,
    )
    product._model = model
    return product


@strawberry.type
class Query:
    @strawberry.field
    def products(self, info) -> List[Product]:
        session = SessionLocal()
        try:
            stmt = (
                select(ProductModel)
                .options(
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.sellers),
                    selectinload(ProductModel.categories),
                    selectinload(ProductModel.images),
                )
                .order_by(ProductModel.id)
            )
            models = session.execute(stmt).scalars().all()
            return [to_product(m) for m in models]
        finally:
            session.close()

    @strawberry.field
    def product(self, info, id: strawberry.ID) -> Optional[Product]:
        session = SessionLocal()
        try:
            stmt = (
                select(ProductModel)
                .where(ProductModel.id == int(id))
                .options(
                    selectinload(ProductModel.reviews),
                    selectinload(ProductModel.sellers),
                    selectinload(ProductModel.categories),
                    selectinload(ProductModel.images),
                )
            )
            model = session.execute(stmt).scalars().first()
            return to_product(model) if model else None
        finally:
            session.close()


schema = strawberry.Schema(query=Query)

app = FastAPI()
graphql_app = GraphQLRouter(schema)
app.include_router(graphql_app, prefix="/graphql")

